// ── Injection function ──────────────────────────────────────────────────────

function injectKindergartenFields(filePath, newFields) {
  const src = fs.readFileSync(filePath, 'utf8');
  // Find the unique pattern: end of kindergarten section + first-grade start
  const marker = /\n    \},\n    'first-grade':/;
  const match = src.match(marker);
  if (!match) {
    throw new Error(`Could not find kindergarten-first-grade boundary in ${filePath}`);
  }
  // Insert the new fields before the closing }, of the kindergarten section
  const insertPos = match.index;
  const updated = src.slice(0, insertPos) + '\n' + newFields + '\n    },\n    \'first-grade\':' + src.slice(match.index + match[0].length);
  fs.writeFileSync(filePath, updated, 'utf8');
  console.log(`  Updated ${path.basename(path.dirname(filePath))}/${path.basename(filePath)}`);
}

